class Solution {
    public int findBestValue(int[] arr, int target) {
        int left = 0, right = 0;
        for (int num : arr) {
            right = Math.max(right, num);
        }
        while (left < right) {
            int mid = left + (right - left) / 2;
            int sum = getSum(arr, mid);
            if (sum < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        int sum1 = getSum(arr, left);
        int sum2 = getSum(arr, left - 1);
        return Math.abs(sum1 - target) >= Math.abs(sum2 - target) ? left - 1 : left;
    }

    private int getSum(int[] arr, int val) {
        int sum = 0;
        for (int num : arr) {
            sum += Math.min(num, val);
        }
        return sum;
    }
}
